func TestAuthHeaderPreservesConfigAuthSource(t *testing.T) {
	cfg := &Config{
		AccessToken: "file-token",
		AuthSource:  "config",
	}

	if got := cfg.AuthHeader(); got != "Bearer file-token" {
		t.Fatalf("AuthHeader: want Bearer file-token, got %q", got)
	}
	if cfg.AuthSource != "config" {
		t.Fatalf("AuthSource should remain config, got %q", cfg.AuthSource)
	}
}

func TestAuthHeaderPrefersExplicitHeaderWithoutChangingSource(t *testing.T) {
	cfg := &Config{
		AuthHeaderVal: "Token direct",
		AuthSource:    "config",
	}

	if got := cfg.AuthHeader(); got != "Token direct" {
		t.Fatalf("AuthHeader: want Token direct, got %q", got)
	}
	if cfg.AuthSource != "config" {
		t.Fatalf("AuthSource should remain config, got %q", cfg.AuthSource)
	}
}

func TestLoadEnvAccessTokenClearsPersistedExpiry(t *testing.T) {
	path := filepath.Join(t.TempDir(), "config.toml")
	cfg := &Config{Path: path}
	if err := cfg.SaveTokens("", "", "file-token", "file-refresh", time.Now().Add(-time.Hour)); err != nil {
		t.Fatalf("SaveTokens: %v", err)
	}

	t.Setenv("GUMROAD_ACCESS_TOKEN", "env-token")

	loaded, err := Load(path)
	if err != nil {
		t.Fatalf("Load: %v", err)
	}
	if loaded.AccessToken != "env-token" {
		t.Fatalf("AccessToken: want env-token, got %q", loaded.AccessToken)
	}
	if loaded.AuthSource != "env:GUMROAD_ACCESS_TOKEN" {
		t.Fatalf("AuthSource: want env:GUMROAD_ACCESS_TOKEN, got %q", loaded.AuthSource)
	}
	if loaded.RefreshToken != "" {
		t.Fatalf("RefreshToken should be cleared for env auth, got %q", loaded.RefreshToken)
	}
	if !loaded.TokenExpiry.IsZero() {
		t.Fatalf("TokenExpiry should be cleared for env auth, got %s", loaded.TokenExpiry)
	}
}
